import { cpSync, existsSync, mkdirSync, readFileSync, rmSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { execFileSync } from "node:child_process";

import { average, parseArgs, parseDurationToMs, requireOption } from "./common.mjs";
import { buildBenchmarkQueries, buildBenchmarkScenarios } from "./benchmark-suite.mjs";

const DESCRIPTION = `
Creates a support bundle for sharing ClickHouse vs InfluxDB 3 benchmark results.

Usage:
  node tools/tx-outcome-storage/export-influxdb-support-bundle.mjs \\
    --report-dir .local-benchmarks/tx-outcome-1773795305434

Optional:
  --out-dir <dir>      bundle directory (default: <report-dir>/influxdb-support-bundle)
  --zip <file.zip>     create a zip archive in addition to the directory
`;

function main() {
  const { options } = parseArgs(process.argv.slice(2));
  if (options.has("help")) {
    process.stdout.write(`${DESCRIPTION.trim()}\n`);
    return;
  }

  const reportDir = resolve(requireOption(options, "report-dir"));
  const outDir = resolve(String(options.get("out-dir") ?? join(reportDir, "influxdb-support-bundle")));
  const zipPath = options.has("zip")
    ? resolve(String(options.get("zip")))
    : `${outDir}.zip`;

  const reportJsonPath = join(reportDir, "benchmark-report.json");
  const reportMdPath = join(reportDir, "benchmark-report.md");
  if (!existsSync(reportJsonPath)) {
    throw new Error(`Missing benchmark report: ${reportJsonPath}`);
  }

  const report = JSON.parse(readFileSync(reportJsonPath, "utf8"));
  const manifest = report.dataset?.manifest;
  if (!manifest) {
    throw new Error(`benchmark-report.json missing dataset.manifest: ${reportJsonPath}`);
  }

  rmSync(outDir, { recursive: true, force: true });
  mkdirSync(outDir, { recursive: true });
  mkdirSync(join(outDir, "queries"), { recursive: true });
  mkdirSync(join(outDir, "dashboards"), { recursive: true });

  cpSync(reportJsonPath, join(outDir, "benchmark-report.json"));
  if (existsSync(reportMdPath)) {
    cpSync(reportMdPath, join(outDir, "benchmark-report.md"));
  }

  const summary = buildExecutiveSummary(report);
  const methodology = buildMethodology(report);
  const mailTemplate = buildMailTemplate(report, summary);
  const querySuite = buildQuerySuite(report);

  writeFileSync(join(outDir, "README.md"), buildBundleReadme(), "utf8");
  writeFileSync(join(outDir, "executive-summary.md"), summary, "utf8");
  writeFileSync(join(outDir, "methodology.md"), methodology, "utf8");
  writeFileSync(join(outDir, "mail-template.md"), mailTemplate, "utf8");
  writeFileSync(join(outDir, "environment.json"), JSON.stringify(buildEnvironment(report), null, 2), "utf8");
  writeFileSync(join(outDir, "queries", "query-suite.md"), renderQuerySuiteMarkdown(querySuite), "utf8");
  writeFileSync(join(outDir, "queries", "query-suite.json"), JSON.stringify(querySuite, null, 2), "utf8");

  copyIfExists("grafana/dashboards/tx-outcomes-influxdb3.json", join(outDir, "dashboards", "tx-outcomes-influxdb3.json"));
  copyIfExists("grafana/dashboards/tx-rtt-overview-influxdb3.json", join(outDir, "dashboards", "tx-rtt-overview-influxdb3.json"));
  copyIfExists("grafana/dashboards/tx-rtt-latency-influxdb3.json", join(outDir, "dashboards", "tx-rtt-latency-influxdb3.json"));
  copyIfExists("grafana/dashboards/tx-rtt-quality-influxdb3.json", join(outDir, "dashboards", "tx-rtt-quality-influxdb3.json"));
  copyIfExists("grafana/dashboards/tx-outcomes-bench-influxdb3.json", join(outDir, "dashboards", "tx-outcomes-bench-influxdb3.json"));
  copyIfExists("grafana/dashboards/tx-outcomes-clickhouse.json", join(outDir, "dashboards", "tx-outcomes-clickhouse.json"));
  copyIfExists("grafana/dashboards/tx-rtt-overview-clickhouse.json", join(outDir, "dashboards", "tx-rtt-overview-clickhouse.json"));
  copyIfExists("grafana/dashboards/tx-rtt-latency-clickhouse.json", join(outDir, "dashboards", "tx-rtt-latency-clickhouse.json"));
  copyIfExists("grafana/dashboards/tx-rtt-quality-clickhouse.json", join(outDir, "dashboards", "tx-rtt-quality-clickhouse.json"));
  copyIfExists("grafana/dashboards/tx-outcomes-bench-clickhouse.json", join(outDir, "dashboards", "tx-outcomes-bench-clickhouse.json"));

  tryCreateZip(outDir, zipPath);

  process.stdout.write(`${outDir}\n`);
  if (existsSync(zipPath)) {
    process.stdout.write(`${zipPath}\n`);
  }
}

function buildBundleReadme() {
  return `# InfluxDB Support Bundle

This bundle is intended for vendor review of the ClickHouse vs InfluxDB 3 read benchmark.

Contents:

- \`executive-summary.md\`: short vendor-facing summary with the main observations
- \`methodology.md\`: dataset, benchmark method, timing semantics, and caveats
- \`mail-template.md\`: ready-to-edit email body
- \`benchmark-report.json\`: full machine-readable benchmark results
- \`benchmark-report.md\`: human-readable report generated by the harness
- \`environment.json\`: dataset and bundle metadata
- \`queries/query-suite.md\`: rendered ClickHouse and InfluxDB SQL for every benchmark window/scenario
- \`queries/query-suite.json\`: same query suite in machine-readable form
- \`dashboards/\`: Grafana dashboards used as the benchmark surface

Recommended send pattern:

1. Put the short conclusion in the email body.
2. Attach the full bundle as ZIP.
3. Ask InfluxDB to focus on:
   - client-observed latency vs server-side timing divergence
   - long-window read latency
   - query shapes that are slow or planner-sensitive
`;
}

function buildEnvironment(report) {
  return {
    generatedAt: report.generatedAt,
    dataset: report.dataset,
    benchmarkEntries: Array.isArray(report.benchmark) ? report.benchmark.length : 0,
    note: "Synthetic read benchmark generated from PocketHive tx_outcome harness."
  };
}

function buildExecutiveSummary(report) {
  const windows = collectWindows(report);
  const lines = [
    "# Executive Summary",
    "",
    "This package compares ClickHouse and InfluxDB 3 on the same synthetic tx_outcome corpus and the same read-oriented query suite.",
    ""
  ];

  for (const window of windows) {
    const clickhouse = averageWarmP95(report, window, "clickhouse");
    const influx = averageWarmP95(report, window, "influxdb3");
    if (clickhouse == null || influx == null) {
      continue;
    }
    const ratio = clickhouse === 0 ? null : influx / clickhouse;
    lines.push(`- ${window}: ClickHouse warm p95 total avg ${formatMs(clickhouse)}, InfluxDB 3 ${formatMs(influx)}${ratio == null ? "" : ` (${formatRatio(ratio)} slower)`}`);
  }

  const worstInflux = worstQueries(report, "influxdb3", 5);
  if (worstInflux.length > 0) {
    lines.push("");
    lines.push("## Worst InfluxDB 3 Queries");
    lines.push("");
    for (const item of worstInflux) {
      lines.push(`- ${item.window} / ${item.scenarioLabel} / ${item.label}: warm p95 total ${formatMs(item.client.warmP95.totalMs)}${item.server?.warmP95?.endToEndMs == null ? "" : `, server warm p95 end-to-end ${formatMs(item.server.warmP95.endToEndMs)}`}`);
    }
  }

  lines.push("");
  lines.push("## Key Interpretation");
  lines.push("");
  lines.push("- ClickHouse is consistently faster on this query surface.");
  lines.push("- For some InfluxDB 3 queries, server-side timing is materially lower than client-observed total latency.");
  lines.push("- The bundle includes both client timing and server-side timing so the discrepancy can be investigated directly.");
  return `${lines.join("\n")}\n`;
}

function buildMethodology(report) {
  const dataset = report.dataset ?? {};
  const manifest = dataset.manifest ?? {};
  return `# Methodology

## Goal

Compare read-path behavior of ClickHouse and InfluxDB 3 for the PocketHive \`tx_outcome\` workload.

## Corpus

- rows: ${dataset.rows}
- synthetic ingest rate used to build the corpus: ${dataset.ratePerSec}/s
- synthetic duration used to build the corpus: ${dataset.durationMinutes} minutes
- history window: ${dataset.historyWindow}
- swarms: ${manifest.swarms}
- callId cardinality: ${manifest.callIdsCount}
- businessCode cardinality: ${manifest.businessCodesCount}
- reference time: ${manifest.referenceTime}

## Query Surface

The benchmark query suite is derived from the Grafana dashboards used to inspect these tx_outcome datasets.

The bundle contains:

- the generated machine-readable report
- the exact ClickHouse and InfluxDB SQL used for every benchmark window/scenario
- the dashboard JSON definitions

## Timing Semantics

- client timings:
  - \`headersMs\`: time until HTTP headers were available
  - \`firstByteMs\`: time until the first byte of the response body
  - \`totalMs\`: time until the full response completed
- InfluxDB 3 server timings:
  - \`planMs\`
  - \`permitMs\`
  - \`executeMs\`
  - \`endToEndMs\`
  - \`computeMs\`

## Scenarios

- \`all-swarms\`: no swarm/call/businessCode filter
- \`single-swarm\`: one swarm only
- \`focused-segment\`: one swarm + hot callId + hot businessCode

## Important Caveat

This particular bundle is based on a synthetic 30-day spread, not a real production export. The query suite and the measurement methodology are production-oriented, but the corpus itself is synthetic.
`;
}

function buildMailTemplate(report, summaryMarkdown) {
  const summaryLines = summaryMarkdown
    .split("\n")
    .filter((line) => line.startsWith("- "))
    .slice(0, 6)
    .map((line) => line.replace(/^- /, "- "));

  return `Subject: PocketHive read benchmark: ClickHouse vs InfluxDB 3

Hi,

Attached is a support bundle with a read-oriented benchmark we ran against the same PocketHive tx_outcome dataset/query surface in ClickHouse and InfluxDB 3.

What is attached:

- full benchmark report (\`benchmark-report.json\` and \`benchmark-report.md\`)
- methodology and timing notes
- exact ClickHouse and InfluxDB SQL for the benchmark suite
- Grafana dashboard JSON used as the benchmark surface

Headline findings:

${summaryLines.join("\n")}

The main point we would like help with is this:

- for several InfluxDB 3 queries, server-side timings are substantially lower than client-observed total latency
- long-window queries are still materially slower than ClickHouse on this workload

Could you review the attached query suite and advise:

1. whether these query shapes are appropriate for InfluxDB 3 SQL / Flight SQL
2. whether there are known issues or settings that explain the client-observed latency gap
3. whether the schema/query style should be changed materially for this workload

If useful, we can rerun the same harness on a real 3-week production export next.

Regards,
`;
}

function buildQuerySuite(report) {
  const manifest = report.dataset.manifest;
  const scenarios = buildBenchmarkScenarios(manifest);
  const referenceTime = manifest.referenceTime ?? report.generatedAt;
  return collectWindows(report).map((window) => ({
    window,
    scenarios: scenarios.map((scenario) => ({
      id: scenario.id,
      label: scenario.label,
      queries: buildBenchmarkQueries({
        clickhouseTable: report.dataset.clickhouseTable,
        influxMeasurement: report.dataset.measurement,
        window,
        scenario,
        referenceTime
      })
    }))
  }));
}

function renderQuerySuiteMarkdown(querySuite) {
  const lines = [
    "# Query Suite",
    "",
    "Rendered benchmark queries used in the support bundle.",
    ""
  ];

  for (const windowSuite of querySuite) {
    lines.push(`## Window: ${windowSuite.window}`);
    lines.push("");
    for (const scenario of windowSuite.scenarios) {
      lines.push(`### Scenario: ${scenario.label}`);
      lines.push("");
      for (const query of scenario.queries) {
        lines.push(`#### ${query.label}`);
        lines.push("");
        lines.push("ClickHouse:");
        lines.push("```sql");
        lines.push(query.clickhouseSql);
        lines.push("```");
        lines.push("");
        lines.push("InfluxDB 3:");
        lines.push("```sql");
        lines.push(query.influxSql);
        lines.push("```");
        lines.push("");
      }
    }
  }

  return `${lines.join("\n")}\n`;
}

function collectWindows(report) {
  return [...new Set((report.benchmark ?? []).map((entry) => entry.window))].sort(
    (left, right) => parseDurationToMs(left, "window") - parseDurationToMs(right, "window")
  );
}

function averageWarmP95(report, window, storage) {
  const values = (report.benchmark ?? [])
    .filter((entry) => entry.window === window && entry.storage === storage && entry.error == null)
    .map((entry) => entry.client?.warmP95?.totalMs)
    .filter((value) => Number.isFinite(value));
  return average(values);
}

function worstQueries(report, storage, limit) {
  return [...(report.benchmark ?? [])]
    .filter((entry) => entry.storage === storage && entry.error == null && Number.isFinite(entry.client?.warmP95?.totalMs))
    .sort((left, right) => right.client.warmP95.totalMs - left.client.warmP95.totalMs)
    .slice(0, limit);
}

function formatMs(value) {
  if (value == null) {
    return "n/a";
  }
  if (value >= 1000) {
    return `${(value / 1000).toFixed(2)} s`;
  }
  return `${value.toFixed(2)} ms`;
}

function formatRatio(value) {
  if (!Number.isFinite(value)) {
    return "n/a";
  }
  return `${value.toFixed(2)}x`;
}

function copyIfExists(from, to) {
  const source = resolve(from);
  if (!existsSync(source)) {
    return;
  }
  mkdirSync(dirname(to), { recursive: true });
  cpSync(source, to);
}

function tryCreateZip(sourceDir, zipPath) {
  try {
    execFileSync(
      "python3",
      [
        "-c",
        [
          "import os, sys, zipfile",
          "src = sys.argv[1]",
          "dst = sys.argv[2]",
          "with zipfile.ZipFile(dst, 'w', compression=zipfile.ZIP_DEFLATED) as zf:",
          "    for root, _dirs, files in os.walk(src):",
          "        for name in files:",
          "            path = os.path.join(root, name)",
          "            zf.write(path, os.path.relpath(path, src))"
        ].join("\n"),
        sourceDir,
        zipPath
      ],
      { stdio: "ignore" }
    );
  } catch {
    // Best-effort ZIP creation only. The bundle directory is still usable.
  }
}

main();
